def zoneinfiltrationdesignflowrate_modifier(constant_term_coefficient: float, temperature_term_coefficient: float, velocity_term_coefficient: float, velocity_squared_term_coefficient: float, t_zone_c: float, t_outdoor_c: float, wind_speed_m_s: float) -> float:
    """Polynomial wind/temperature modifier on the design flow."""
    dt = abs(t_zone_c - t_outdoor_c)
    v = max(0.0, wind_speed_m_s)
    return (
        constant_term_coefficient
        + temperature_term_coefficient * dt
        + velocity_term_coefficient * v
        + velocity_squared_term_coefficient * v * v
    )

def zonemixing_is_active(delta_temperature_c: float, t_source_c: float, t_target_c: float) -> float:
    """Return whether the source/target temperature gating allows flow."""
    return abs(t_source_c - t_target_c) >= delta_temperature_c

_DP_REG_PA = 0.0001

def flowcomponent_derivative(coefficient: float, exponent: float, dp_pa: float) -> float:
    """Return ``dm/dΔP`` (kg/s/Pa). Always >= 0."""
    ap = max(abs(dp_pa), _DP_REG_PA)
    return coefficient * exponent * (ap ** (exponent - 1.0))

