def stepped_power_reduction_factor(
    illuminance_lux: float,
    setpoint_lux: float,
) -> float:
    """Stepped control: 1.0 (full power) below setpoint, 0.0 above.

    Simplification of upstream's N-step quantiser to a single threshold.
    Matches the IDD default ``number_of_stepped_control_steps`` of 1.
    """
    if setpoint_lux <= 0.0:
        return 1.0
    if illuminance_lux >= setpoint_lux:
        return 0.0
    return 1.0

def _area_mismatch_pct(a: float, b: float) -> float:
    """Symmetric percent difference relative to the larger of the two."""
    denom = max(abs(a), abs(b))
    if denom == 0.0:
        return 0.0
    return 100.0 * abs(a - b) / denom

def _np_bulk_fraction(
    heating_w: float,
    cooling_w: float,
    h_total_cap: float,
    c_total_cap: float,
) -> float:
    """Pure-NumPy fallback for plant_plr_bulk_fraction."""
    h_plr = min(max(heating_w, 0.0) / h_total_cap, 1.0) if h_total_cap > 0.0 else 0.0
    c_plr = min(max(cooling_w, 0.0) / c_total_cap, 1.0) if c_total_cap > 0.0 else 0.0
    return max(h_plr, c_plr)

def _stepped_numpy_fallback(illuminance_lux: float, setpoint_lux: float) -> float:
    """NumPy reference for stepped_dimming_power_factor."""
    if setpoint_lux <= 0.0:
        return 1.0
    return 0.0 if illuminance_lux >= setpoint_lux else 1.0

def _continuous_numpy_fallback(
    illuminance_lux: float,
    setpoint_lux: float,
    min_power_fraction: float,
    min_light_fraction: float,
) -> float:
    """NumPy reference for continuous_dimming_power_factor."""
    if setpoint_lux <= 0.0:
        return 1.0
    illum = max(0.0, illuminance_lux)
    fl = (setpoint_lux - illum) / setpoint_lux
    fl = max(0.0, min(1.0, fl))
    if fl >= 1.0:
        return 1.0
    if fl <= 0.0:
        return float(min_power_fraction)
    denom = 1.0 - min_light_fraction
    if denom <= 0.0:
        return float(min_power_fraction)
    if fl <= min_light_fraction:
        return float(min_power_fraction)
    fp = (fl + (1.0 - fl) * min_power_fraction - min_light_fraction) / denom
    fp = max(min_power_fraction, min(1.0, fp))
    return float(fp)

