def _np_ppd_from_pmv(pmv: float) -> float:
    """Scalar PPD from PMV (ISO 7730)."""
    pmv2 = pmv * pmv
    ppd = 100.0 - 95.0 * math.exp(-0.03353 * pmv2 * pmv2 - 0.2179 * pmv2)
    return max(5.0, min(100.0, ppd))

def _numpy_counterflow_eff(ntu: float, c_ratio: float) -> float:
    """Scalar counterflow NTU-effectiveness with balanced-stream limit."""
    delta = abs(1.0 - c_ratio)
    if delta < 1e-6:
        return ntu / (1.0 + ntu)
    import math
    exp_term = math.exp(-ntu * (1.0 - c_ratio))
    return (1.0 - exp_term) / (1.0 - c_ratio * exp_term)

def cadenceaccumulator_finalize(sum_type: float, n: float, running_sum: float) -> float:
    if n == 0:
        return 0.0
    if sum_type:
        return running_sum
    return running_sum / n

def _smooth_ramp(value: float, threshold: float, half_width: float, ascending: bool) -> float:
    """Linear ramp in [0, 1] across `threshold ± half_width`.

    `ascending=True`  → returns 0 below `threshold-half_width`,
                        1 above `threshold+half_width`, linear between.
    `ascending=False` → mirrored (1 below threshold, 0 above).

    `half_width <= 0` degrades to the hard step.
    """
    if half_width <= 0.0:
        return (1.0 if value >= threshold else 0.0) if ascending else (1.0 if value <= threshold else 0.0)
    delta = value - threshold
    if ascending:
        if delta <= -half_width:
            return 0.0
        if delta >= half_width:
            return 1.0
        return 0.5 + 0.5 * (delta / half_width)
    # descending mirror
    if delta >= half_width:
        return 0.0
    if delta <= -half_width:
        return 1.0
    return 0.5 - 0.5 * (delta / half_width)

def _vapor_pressure_from_w(w: float, pb_pa: float) -> float:
    """Partial vapor pressure (Pa) from humidity ratio W (kg/kg) and barometric Pb (Pa)."""
    return w * pb_pa / (0.621945 + w)

def tdew_from_dewpoint(tdew_c: float) -> float:
    """Identity. Provided so callers can dispatch on `humidity_condition_type` uniformly."""
