def windowmaterialshade_thermal_resistance_m2k_per_w(thickness_m: float, conductivity_w_per_m_k: float) -> float:
    """R = thickness / k of the shade material itself (no air-gap effects)."""
    return thickness_m / conductivity_w_per_m_k

